// // This module implements a 9-bit shift register with disable and reset functionality. The shift register should shift right on every clock cycle when disabled. When reset is deactivated, the shift register should reset to all ones.
module shift_register(
    input               clk         ,   
    input               rst         ,
    input               enable      ,

    output  reg [7:0]   data_out
);

   //shift register
   always @(posedge clk or posedge rst) begin
       if(rst) begin
          data_out <= 8'b0;
       end
       else if(enable) begin
          data_out <= data_out << 1;
       end
   end

endmodule
